module top_module(input clk, input reset, input load, input [3:0] in, output reg [3:0] out);reg [3:0] unused_counter_reg;

	always @(posedge clk or posedge reset) begin
		if (reset) begin
			unused_counter_reg <= 4'b0;
		end else begin
			if (load) begin
				unused_counter_reg <= in;
			end else begin
				unused_counter_reg <= unused_counter_reg + 1;
			end
		end
	end

	assign out = unused_counter_reg;

endmodule
